        $max_file_size = $max_file_size ?? 1048576;
        $max_file_size = max(1024, min(10485760, $max_file_size));
        $force_reindex = $force_reindex ?? false;
        $timeout = $timeout ?? 30;
        $timeout = max(5, min(60, $timeout));
        $start = microtime(true);

        $workspace = getcwd() . DIRECTORY_SEPARATOR . 'storage' . DIRECTORY_SEPARATOR . 'agent' . DIRECTORY_SEPARATOR . 'workspace';
        $db_path = $workspace . DIRECTORY_SEPARATOR . $db_name;

        $ext_list = array_map('trim', explode(',', $extensions));
        $ext_set = [];
        foreach ($ext_list as $e) {
            if ($e !== '') $ext_set[strtolower($e)] = true;
        }

        try {
            $pdo = new PDO("sqlite:{$db_path}", null, null, [
                PDO::ATTR_ERRMODE => PDO::ERRMODE_EXCEPTION,
                PDO::ATTR_DEFAULT_FETCH_MODE => PDO::FETCH_ASSOC,
            ]);
            $pdo->exec("PRAGMA journal_mode=WAL");
            $pdo->exec("PRAGMA synchronous=OFF");
        } catch (\Throwable $e) {
            return ['error' => 'Database error: ' . $e->getMessage()];
        }

        if ($mode === 'stats') {
            try {
                $tables = $pdo->query("SELECT name FROM sqlite_master WHERE type='table' AND name='file_contents'")->fetchAll();
                if (empty($tables)) {
                    return ['error' => 'No index found. Run mode=index first.', 'db' => $db_name];
                }
                $count = $pdo->query("SELECT COUNT(*) AS cnt FROM file_contents")->fetch();
                $files = $pdo->query("SELECT COUNT(DISTINCT file_path) AS cnt FROM file_contents")->fetch();
                $size = $pdo->query("SELECT SUM(LENGTH(line_content)) AS total FROM file_contents")->fetch();
                $elapsed = round(microtime(true) - $start, 4);
                return [
                    'success' => true,
                    'mode' => 'stats',
                    'db' => $db_name,
                    'total_lines' => (int)$count['cnt'],
                    'total_files' => (int)$files['cnt'],
                    'total_content_bytes' => (int)$size['total'],
                    'elapsed_seconds' => $elapsed,
                ];
            } catch (\Throwable $e) {
                return ['error' => 'Stats error: ' . $e->getMessage()];
            }
        }

        if ($mode === 'search') {
            try {
                $tables = $pdo->query("SELECT name FROM sqlite_master WHERE type='table' AND name='file_contents_fts'")->fetchAll();
                if (empty($tables)) {
                    return ['error' => 'No FTS5 index found. Run mode=index first.', 'db' => $db_name];
                }
            } catch (\Throwable $e) {
                return ['error' => 'Index check failed: ' . $e->getMessage()];
            }
            
            if (empty($query)) {
                return ['error' => 'Search query is required for mode=search.'];
            }
            
            try {
                // Escape the query for FTS5 (prevent SQL injection via the query itself)
                // We use a safe approach: bind the query as a parameter in a MATCH clause
                $stmt = $pdo->prepare("
                    SELECT fc.id, fc.file_path, fc.line_number, fc.line_content,
                           snippet(file_contents_fts, 2, '<mark>', '</mark>', '...', 40) AS snippet
                    FROM file_contents_fts fts
                    JOIN file_contents fc ON fts.rowid = fc.id
                    WHERE file_contents_fts MATCH ?
                    ORDER BY rank
                    LIMIT ?
                ");
                $stmt->execute([$query, $max_results]);
                $rows = $stmt->fetchAll();
                
                if (empty($rows)) {
                    // Try without FTS5 syntax - maybe the query has special chars
                    // Wrap in quotes for phrase search
                    $simple_query = '"' . str_replace('"', '', $query) . '"';
                    $stmt = $pdo->prepare("
                        SELECT fc.id, fc.file_path, fc.line_number, fc.line_content,
                               snippet(file_contents_fts, 2, '<mark>', '</mark>', '...', 40) AS snippet
                        FROM file_contents_fts fts
                        JOIN file_contents fc ON fts.rowid = fc.id
                        WHERE file_contents_fts MATCH ?
                        LIMIT ?
                    ");
                    $stmt->execute([$simple_query, $max_results]);
                    $rows = $stmt->fetchAll();
                }
                
                $elapsed = round(microtime(true) - $start, 4);
                
                // Group by file
                $files_matched = [];
                $file_lines = [];
                foreach ($rows as $r) {
                    $fp = $r['file_path'];
                    if (!isset($file_lines[$fp])) {
                        $file_lines[$fp] = [];
                        $files_matched[] = $fp;
                    }
                    $file_lines[$fp][] = [
                        'line' => (int)$r['line_number'],
                        'content' => $r['line_content'],
                        'snippet' => $r['snippet'],
                    ];
                }
                
                $results = [];
                foreach ($files_matched as $fp) {
                    $results[] = [
                        'file' => $fp,
                        'matches' => count($file_lines[$fp]),
                        'lines' => $file_lines[$fp],
                    ];
                }
                
                return [
                    'success' => true,
                    'mode' => 'search',
                    'query' => $query,
                    'total_matches' => count($rows),
                    'files_matched' => count($files_matched),
                    'elapsed_seconds' => $elapsed,
                    'results' => $results,
                ];
            } catch (\Throwable $e) {
                return ['error' => 'Search failed: ' . $e->getMessage() . ' (query: ' . $query . ')'];
            }
        }

        // Index mode
        if ($mode === 'index') {
            // Create/reset FTS5 tables
            if ($force_reindex) {
                $pdo->exec("DROP TABLE IF EXISTS file_contents");
            }
            
            try {
                $pdo->exec("CREATE TABLE IF NOT EXISTS file_contents (
                    id INTEGER PRIMARY KEY AUTOINCREMENT,
                    file_path TEXT NOT NULL,
                    line_number INTEGER NOT NULL,
                    line_content TEXT NOT NULL,
                    file_extension TEXT NOT NULL
                )");
                $pdo->exec("CREATE VIRTUAL TABLE IF NOT EXISTS file_contents_fts USING fts5(
                    file_path, line_content, file_extension,
                    content='file_contents',
                    content_rowid='id',
                    tokenize='porter unicode61'
                )");
            } catch (\Throwable $e) {
                return ['error' => 'Failed to create tables: ' . $e->getMessage()];
            }
            
            // Resolve path
            $root = getcwd();
            $target_path = $path;
            if (strpos($path, DIRECTORY_SEPARATOR) !== 0 && strpos($path, ':') === false) {
                $target_path = $root . DIRECTORY_SEPARATOR . ltrim($path, '/' . DIRECTORY_SEPARATOR);
            }
            
            if (!is_dir($target_path)) {
                return ['error' => 'Directory not found: ' . $path, 'resolved' => $target_path];
            }
            
            // Create a file iterator
            $files_scanned = 0;
            $files_indexed = 0;
            $lines_indexed = 0;
            $skipped_binary = 0;
            $skipped_size = 0;
            $skipped_ext = 0;
            
            // Get existing indexed files to avoid re-indexing unchanged files
            $existing_files = [];
            try {
                $ef = $pdo->query("SELECT DISTINCT file_path FROM file_contents")->fetchAll();
                foreach ($ef as $e) {
                    $existing_files[$e['file_path']] = true;
                }
            } catch (\Throwable $e) {
                // Fresh database
            }
            
            $it = new RecursiveIteratorIterator(
                new RecursiveDirectoryIterator($target_path, RecursiveDirectoryIterator::SKIP_DOTS)
            );
            
            $pdo->beginTransaction();
            
            foreach ($it as $fileinfo) {
                // Check timeout
                if (microtime(true) - $start > $timeout) {
                    break;
                }
                
                $files_scanned++;
                $file_path_real = $fileinfo->getPathname();
                $rel_path = str_replace($root . DIRECTORY_SEPARATOR, '', $file_path_real);
                
                // Skip directories we shouldn't touch
                if (preg_match('#[/\\\\](vendor|node_modules|\\.git|\\.svn|_build|dist|build)[/\\\\]#', $rel_path)) {
                    continue;
                }
                
                if (!$fileinfo->isFile() || !$fileinfo->isReadable()) continue;
                
                $ext = strtolower($fileinfo->getExtension());
                if (!isset($ext_set[$ext])) {
                    $skipped_ext++;
                    continue;
                }
                
                $size = $fileinfo->getSize();
                if ($size > $max_file_size) {
                    $skipped_size++;
                    continue;
                }
                if ($size === 0) continue;
                
                // Skip if already indexed and file hasn't changed
                $mtime = $fileinfo->getMTime();
                
                $content = @file_get_contents($file_path_real, false, null, 0, $max_file_size);
                if ($content === false) continue;
                
                // Detect binary content
                if (mb_detect_encoding($content, 'UTF-8,ISO-8859-1,ASCII', true) === false && preg_match('/[\x00-\x08\x0E-\x1F]/', $content)) {
                    $skipped_binary++;
                    continue;
                }
                
                // Index each line
                $lines = explode("\n", $content);
                $line_num = 0;
                $rel_path_db = str_replace('\\', '/', $rel_path);
                
                foreach ($lines as $line_content) {
                    $line_num++;
                    $line_content = trim($line_content);
                    if ($line_content === '') continue;
                    
                    try {
                        $stmt = $pdo->prepare("INSERT INTO file_contents (file_path, line_number, line_content, file_extension) VALUES (?, ?, ?, ?)");
                        $stmt->execute([$rel_path_db, $line_num, mb_substr($line_content, 0, 1000), $ext]);
                        $lines_indexed++;
                    } catch (\Throwable $e) {
                        // Skip problematic lines
                    }
                    
                    // Limit total lines per file to prevent huge files from dominating
                    if ($line_num > 50000) break;
                }
                
                $files_indexed++;
            }
            
            $pdo->commit();
            
            // Rebuild FTS index from content table
            try {
                $pdo->exec("INSERT INTO file_contents_fts (file_path, line_content, file_extension) 
                    SELECT file_path, line_content, file_extension FROM file_contents");
                // Remove duplicates from FTS
                $pdo->exec("DELETE FROM file_contents_fts WHERE rowid NOT IN (SELECT MIN(rowid) FROM file_contents_fts GROUP BY file_path, line_content)");
            } catch (\Throwable $e) {
                return ['error' => 'FTS rebuild failed: ' . $e->getMessage()];
            }
            
            // Optimize
            try {
                $pdo->exec("INSERT INTO file_contents_fts(file_contents_fts) VALUES('optimize')");
            } catch (\Throwable $e) {
                // Non-critical
            }
            
            $elapsed = round(microtime(true) - $start, 4);
            
            return [
                'success' => true,
                'mode' => 'index',
                'db' => $db_name,
                'path_indexed' => $path,
                'files_scanned' => $files_scanned,
                'files_indexed' => $files_indexed,
                'lines_indexed' => $lines_indexed,
                'skipped_extension' => $skipped_ext,
                'skipped_size' => $skipped_size,
                'skipped_binary' => $skipped_binary,
                'extensions' => $extensions,
                'max_file_size' => $max_file_size,
                'elapsed_seconds' => $elapsed,
            ];
        }

        return ['error' => 'Unknown mode: ' . $mode . '. Use index, search, or stats.'];
    }
